import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import Home from './pages/Home/Home';
import Search from './pages/Search/Search';
import Ranking from './pages/Ranking/Ranking';
import Profile from './pages/Profile/Profile';
import FocusMode from './pages/Focus/FocusMode';
import Login from './pages/Auth/Login';
import Register from './pages/Auth/Register';
import AdminUpload from './pages/Admin/AdminUpload';

function App() {
  // 1. Lấy thông tin user từ localStorage khi load trang
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')));

  // Cập nhật lại user mỗi khi localStorage thay đổi (giúp đồng bộ khi login/logout)
  useEffect(() => {
    const storedUser = JSON.parse(localStorage.getItem('user'));
    setUser(storedUser);
  }, []);

  // 2. Hàm đăng xuất
  const handleLogout = () => {
    localStorage.clear();
    setUser(null);
    window.location.href = '/login';
  };

  return (
    <Router>
      {/* THANH ĐIỀU HƯỚNG (NAVBAR) */}
      <nav style={navBarStyle}>
        <div style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
          <Link to="/" style={logoStyle}>
            P2TUNES
          </Link>
          <Link to="/search" style={navLinkStyle}>Tìm kiếm</Link>
          <Link to="/ranking" style={navLinkStyle}>BXH</Link>
          <Link to="/focus" style={navLinkStyle}>Focus</Link>
          
          {/* Nút Upload - Chỉ hiện khi đã đăng nhập */}
          {user && (
            <Link to="/upload" style={uploadBtnStyle}>+ Upload</Link>
          )}
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
          {user ? (
            <>
              {/* QUAN TRỌNG: Link Profile luôn kèm theo ID của user */}
              <Link 
                to={`/profile/${user._id || user.id}`} 
                style={{ textDecoration: 'none', color: 'white' }}
              >
                Xin chào, <b style={{ textDecoration: 'underline' }}>{user.username}</b>
              </Link>
              <button 
                onClick={handleLogout} 
                style={logoutBtnStyle}
              >
                Thoát
              </button>
            </>
          ) : (
            <div style={{ display: 'flex', gap: '15px' }}>
              <Link to="/login" style={navLinkStyle}>Đăng nhập</Link>
              <Link to="/register" style={registerBtnStyle}>Đăng ký</Link>
            </div>
          )}
        </div>
      </nav>

      {/* CẤU HÌNH CÁC TUYẾN ĐƯỜNG (ROUTES) */}
      <div style={{ minHeight: '80vh' }}>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/search" element={<Search />} />
          <Route path="/ranking" element={<Ranking />} />
          
          <Route 
            path="/profile/:userId" 
            element={<Profile key={window.location.pathname} />}
            />
          
          <Route path="/focus" element={<FocusMode />} />
          <Route path="/upload" element={<AdminUpload />} />
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
        </Routes>
      </div>

      {/* FOOTER ĐƠN GIẢN */}
      <footer style={footerStyle}>
        © 2024 P2TUNES - Nền tảng chia sẻ âm nhạc miễn phí
      </footer>
    </Router>
  );
}
